import { Effect, Layer, Context } from "effect";

interface Config { readonly baseUrl: string }
const Config = Context.GenericTag<Config>("app/Config");

interface Logger { readonly info: (msg: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger");

interface HttpClient { readonly get: (path: string) => Effect.Effect<string> }
const HttpClient = Context.GenericTag<HttpClient>("app/HttpClient");

const ConfigLive = Layer.succeed(Config, { baseUrl: "https://api.example.com" });

// Logger depends on Config (reads baseUrl for log prefixing)
const LoggerLive = Layer.effect(
  Logger,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return Logger.of({ info: (msg) => Effect.sync(() => console.log(`[${cfg.baseUrl}] ${msg}`)) });
  })
);

const HttpClientLive = Layer.succeed(HttpClient, {
  get: (path) => Effect.succeed(`GET ${path}`)
});

const LiveLayer = Layer.merge(ConfigLive, Layer.merge(LoggerLive, HttpClientLive));

const program = Effect.gen(function* () {
  const log = yield* Logger;
  const http = yield* HttpClient;
  yield* log.info("starting");
  return yield* http.get("/users");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`Logger` is built with `Layer.effect` because it needs the `Config` service at construction time; `Layer.merge` then composes all three into the final `LiveLayer` that `Effect.provide` injects into the program.

