```ts
import { Effect, Layer, Context } from "effect";

interface Clock { readonly now: () => Effect.Effect<number> }
const Clock = Context.GenericTag<Clock>("app/Clock");

interface Cache {
  readonly get: (k: string) => Effect.Effect<string | null>;
  readonly set: (k: string, v: string) => Effect.Effect<void>;
}
const Cache = Context.GenericTag<Cache>("app/Cache");

const ClockLive = Layer.succeed(Clock, { now: () => Effect.sync(() => Date.now()) });

// Cache depends on Clock (stamps entries with ts)
const CacheLive = Layer.effect(
  Cache,
  Effect.gen(function* () {
    const clock = yield* Clock;
    const store = new Map<string, { v: string; t: number }>();
    return Cache.of({
      get: (k) => Effect.sync(() => store.get(k)?.v ?? null),
      set: (k, v) => Effect.gen(function* () {
        const t = yield* clock.now();
        store.set(k, { v, t });
      })
    });
  })
);

const LiveLayer = Layer.merge(ClockLive, CacheLive);

const program = Effect.gen(function* () {
  const cache = yield* Cache;
  yield* cache.set("k", "v");
  return yield* cache.get("k");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`Layer.effect` takes the `Cache` tag (not a string) and the construction effect that yields `Clock`; `Layer.merge` stitches the two so the final effect has `never` in its R channel.

