import { Effect, Layer, Context } from "effect";

interface FsConfig { readonly workDir: string }
const FsConfig = Context.GenericTag<FsConfig>("fs/Config");

interface Fs {
  readonly read: (p: string) => Effect.Effect<string>;
  readonly write: (p: string, data: string) => Effect.Effect<void>;
}
const Fs = Context.GenericTag<Fs>("fs/Fs");

const FsConfigLive = Layer.succeed(FsConfig, { workDir: "/tmp/app" });

// Fs depends on FsConfig; scoped so working dir is cleaned on shutdown
const FsLive = Layer.scoped(
  Fs,
  Effect.gen(function* () {
    const cfg = yield* FsConfig;
    yield* Effect.acquireRelease(
      Effect.sync(() => console.log(`mkdir ${cfg.workDir}`)),
      () => Effect.sync(() => console.log(`rmdir ${cfg.workDir}`))
    );
    return Fs.of({
      read: (p) => Effect.succeed(`contents of ${cfg.workDir}/${p}`),
      write: (p, data) => Effect.sync(() => console.log(`write ${cfg.workDir}/${p}: ${data.length}B`))
    });
  })
);

const LiveLayer = Layer.merge(FsConfigLive, FsLive);

const program = Effect.gen(function* () {
  const fs = yield* Fs;
  yield* fs.write("a.txt", "hi");
  return yield* fs.read("a.txt");
});

export const runnable = Effect.provide(program, LiveLayer);
