```ts
import { Effect, Layer, Context } from "effect";

interface Queue { readonly pop: () => Effect.Effect<string | null> }
const Queue = Context.GenericTag<Queue>("jobs/Queue");

interface JobRunner { readonly run: (job: string) => Effect.Effect<void> }
const JobRunner = Context.GenericTag<JobRunner>("jobs/JobRunner");

interface Supervisor { readonly tick: () => Effect.Effect<void> }
const Supervisor = Context.GenericTag<Supervisor>("jobs/Supervisor");

const QueueLive = Layer.succeed(Queue, {
  pop: () => Effect.succeed("noop")
});

// JobRunner depends on Queue
const JobRunnerLive = Layer.effect(
  JobRunner,
  Effect.gen(function* () {
    const q = yield* Queue;
    return JobRunner.of({
      run: (job) => Effect.sync(() => console.log(`run ${job}, queue=${q.pop.name}`))
    });
  })
);

// Supervisor depends on JobRunner (and transitively Queue)
const SupervisorLive = Layer.effect(
  Supervisor,
  Effect.gen(function* () {
    const runner = yield* JobRunner;
    const q = yield* Queue;
    return Supervisor.of({
      tick: () => Effect.gen(function* () {
        const job = yield* q.pop();
        if (job) yield* runner.run(job);
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(QueueLive, JobRunnerLive, SupervisorLive);

const program: Effect.Effect<void, never, Supervisor> = Effect.gen(function* () {
  const sup = yield* Supervisor;
  yield* sup.tick();
});

export const runnable = Effect.provide(program, LiveLayer);
```

Supervisor explicitly yields both direct and transitive dependencies; `Layer.mergeAll` satisfies them in the bundle and `Effect.provide` retires the R channel.

`Layer.merge` places two independent layers side by side in the same requirement set. `Layer.provide(inner, outer)` is directional: it feeds `outer` into `inner`, erasing `inner`'s dependency from the resulting layer. Use it when a sub-layer still has an unmet requirement that you want to close off locally.

