```ts
import { Effect, Layer, Context } from "effect";

interface SecretConfig { readonly apiKey: string }
const SecretConfig = Context.GenericTag<SecretConfig>("app/SecretConfig");

interface BillingClient { readonly charge: (n: number) => Effect.Effect<string> }
const BillingClient = Context.GenericTag<BillingClient>("app/BillingClient");

interface App { readonly run: () => Effect.Effect<string> }
const App = Context.GenericTag<App>("app/App");

const SecretConfigLive = Layer.succeed(SecretConfig, { apiKey: "sk_live_..." });

// BillingClient depends on SecretConfig
const BillingClientNeedsSecret = Layer.effect(
  BillingClient,
  Effect.gen(function* () {
    const sec = yield* SecretConfig;
    return BillingClient.of({
      charge: (n) => Effect.succeed(`${sec.apiKey.slice(0,3)}:${n}`)
    });
  })
);

// Close off SecretConfig only for BillingClient -- App never sees it
const BillingClientLive = Layer.provide(BillingClientNeedsSecret, SecretConfigLive);

// App depends only on BillingClient
const AppLive = Layer.effect(
  App,
  Effect.gen(function* () {
    const b = yield* BillingClient;
    return App.of({ run: () => b.charge(42) });
  })
);

const LiveLayer = Layer.merge(BillingClientLive, AppLive);

const program = Effect.gen(function* () {
  const app = yield* App;
  return yield* app.run();
});

export const runnable = Effect.provide(program, LiveLayer);
```

After `Layer.provide(BillingClientNeedsSecret, SecretConfigLive)`, nothing else in the graph can accidentally yield `SecretConfig` — the secret is encapsulated to one sub-layer.

```ts
import { Effect, Layer, Context } from "effect";

interface SearchConfig { readonly indexPath: string }
const SearchConfig = Context.GenericTag<SearchConfig>("search/Config");

interface IndexReader { readonly lookup: (term: string) => Effect.Effect<ReadonlyArray<string>> }
const IndexReader = Context.GenericTag<IndexReader>("search/IndexReader");

interface QueryParser { readonly parse: (q: string) => Effect.Effect<ReadonlyArray<string>> }
const QueryParser = Context.GenericTag<QueryParser>("search/QueryParser");

interface SearchService { readonly search: (q: string) => Effect.Effect<ReadonlyArray<string>> }
const SearchService = Context.GenericTag<SearchService>("search/SearchService");

const SearchConfigLive = Layer.succeed(SearchConfig, { indexPath: "/var/idx" });
const QueryParserLive = Layer.succeed(QueryParser, {
  parse: (q) => Effect.succeed(q.split(/\s+/))
});

// IndexReader depends on SearchConfig
const IndexReaderLive = Layer.effect(
  IndexReader,
  Effect.gen(function* () {
    const cfg = yield* SearchConfig;
    return IndexReader.of({
      lookup: (term) => Effect.succeed([`${cfg.indexPath}:hit-${term}`])
    });
  })
);

// SearchService depends on IndexReader + QueryParser
const SearchServiceLive = Layer.effect(
  SearchService,
  Effect.gen(function* () {
    const reader = yield* IndexReader;
    const parser = yield* QueryParser;
    return SearchService.of({
      search: (q) => Effect.gen(function* () {
        const terms = yield* parser.parse(q);
        const hits: Array<string> = [];
        for (const term of terms) hits.push(...(yield* reader.lookup(term)));
        return hits;
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(SearchConfigLive, QueryParserLive, IndexReaderLive, SearchServiceLive);

const program = Effect.gen(function* () {
  const s = yield* SearchService;
  return yield* s.search("effect layer");
});

export const runnable = Effect.provide(program, LiveLayer);
```

Four tags, three dependencies, one `Effect.provide`: `Layer.mergeAll` resolves the graph once at provide time.

```ts
import { Effect, Layer, Context } from "effect";

interface Config { readonly apiUrl: string }
const Config = Context.GenericTag<Config>("app/Config");

interface HttpClient { readonly get: (p: string) => Effect.Effect<string> }
const HttpClient = Context.GenericTag<HttpClient>("app/HttpClient");

interface UserApi { readonly me: () => Effect.Effect<string> }
const UserApi = Context.GenericTag<UserApi>("app/UserApi");

const ConfigLive = Layer.succeed(Config, { apiUrl: "https://prod.example" });

// HttpClient depends on Config (production)
const HttpClientProd = Layer.effect(
  HttpClient,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return HttpClient.of({ get: (p) => Effect.succeed(`GET ${cfg.apiUrl}${p}`) });
  })
);

// HttpClient stub (test) -- no Config needed
const HttpClientTest = Layer.succeed(HttpClient, {
  get: (p) => Effect.succeed(`stub:${p}`)
});

// UserApi depends on HttpClient regardless of env
const UserApiLive = Layer.effect(
  UserApi,
  Effect.gen(function* () {
    const http = yield* HttpClient;
    return UserApi.of({ me: () => http.get("/me") });
  })
);

const LiveLayer = Layer.mergeAll(ConfigLive, HttpClientProd, UserApiLive);
const TestLayer = Layer.merge(HttpClientTest, UserApiLive);

const program = Effect.gen(function* () {
  const api = yield* UserApi;
  return yield* api.me();
});

export const runLive = Effect.provide(program, LiveLayer);
export const runTest = Effect.provide(program, TestLayer);
```

The program is environment-agnostic; only the `Effect.provide` boundary decides which `HttpClient` implementation is active.

