import { Effect, Layer, Context } from "effect";

interface AuthConfig { readonly jwksUrl: string }
const AuthConfig = Context.GenericTag<AuthConfig>("auth/Config");

interface KeyVerifier { readonly verify: (token: string) => Effect.Effect<boolean> }
const KeyVerifier = Context.GenericTag<KeyVerifier>("auth/KeyVerifier");

const AuthConfigLive = Layer.succeed(AuthConfig, {
  jwksUrl: "https://auth.example.com/.well-known/jwks.json"
});

// KeyVerifier depends on AuthConfig; initialization is async (JWKS fetch)
const KeyVerifierLive = Layer.effect(
  KeyVerifier,
  Effect.gen(function* () {
    const cfg = yield* AuthConfig;
    const keys = yield* Effect.promise(async () => {
      // simulate JWKS fetch
      return { url: cfg.jwksUrl, keys: ["k1", "k2"] };
    });
    return KeyVerifier.of({
      verify: (token) => Effect.succeed(keys.keys.some((k) => token.includes(k)))
    });
  })
);

const LiveLayer = Layer.merge(AuthConfigLive, KeyVerifierLive);

const program = Effect.gen(function* () {
  const kv = yield* KeyVerifier;
  return yield* kv.verify("k1.signature");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`Layer.effect`'s construction effect can do anything an `Effect` can — including awaiting a promise — so one-time async warmup fits naturally at layer-build time.

```ts
import { Effect, Layer, Context } from "effect";

interface WorkerConfig { readonly intervalMs: number; readonly name: string }
const WorkerConfig = Context.GenericTag<WorkerConfig>("w/Config");

interface Clock { readonly now: () => Effect.Effect<number> }
const Clock = Context.GenericTag<Clock>("w/Clock");

interface Scheduler { readonly tickAt: () => Effect.Effect<number> }
const Scheduler = Context.GenericTag<Scheduler>("w/Scheduler");

interface Worker { readonly run: () => Effect.Effect<string> }
const Worker = Context.GenericTag<Worker>("w/Worker");

const WorkerConfigLive = Layer.succeed(WorkerConfig, { intervalMs: 1000, name: "w1" });
const ClockLive = Layer.succeed(Clock, { now: () => Effect.sync(() => Date.now()) });

// Scheduler depends on Clock
const SchedulerLive = Layer.effect(
  Scheduler,
  Effect.gen(function* () {
    const clk = yield* Clock;
    return Scheduler.of({ tickAt: () => clk.now() });
  })
);

// Worker depends on Scheduler + WorkerConfig
const WorkerLive = Layer.effect(
  Worker,
  Effect.gen(function* () {
    const sch = yield* Scheduler;
    const cfg = yield* WorkerConfig;
    return Worker.of({
      run: () => Effect.gen(function* () {
        const t = yield* sch.tickAt();
        return `${cfg.name}@${t}+${cfg.intervalMs}`;
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(WorkerConfigLive, ClockLive, SchedulerLive, WorkerLive);

const program: Effect.Effect<string, never, Worker> = Effect.gen(function* () {
  const w = yield* Worker;
  return yield* w.run();
});

export const runnable = Effect.provide(program, LiveLayer);
```

Four tags, a fan-in at Worker, and `Layer.mergeAll` to wire them — Effect's type checker refuses the build if any requirement is still open at `provide` time.

```ts
import { Effect, Layer, Context } from "effect";

interface Auth { readonly check: (token: string) => Effect.Effect<string | null> }
const Auth = Context.GenericTag<Auth>("auth/Auth");

interface SessionStore { readonly get: (uid: string) => Effect.Effect<string | null> }
const SessionStore = Context.GenericTag<SessionStore>("auth/SessionStore");

interface App { readonly whoami: (token: string) => Effect.Effect<string> }
const App = Context.GenericTag<App>("app/App");

const AuthLive = Layer.succeed(Auth, {
  check: (t) => Effect.succeed(t.startsWith("tok_") ? t.slice(4) : null)
});

// SessionStore depends on Auth
const SessionStoreLive = Layer.effect(
  SessionStore,
  Effect.gen(function* () {
    const a = yield* Auth;
    return SessionStore.of({
      get: (uid) => Effect.map(a.check(`tok_${uid}`), (u) => u ? `session:${u}` : null)
    });
  })
);

// Sub-bundle: exposes Auth + SessionStore together
const AuthBundle = Layer.mergeAll(AuthLive, SessionStoreLive);

// App depends on SessionStore (and transitively Auth)
const AppLive = Layer.effect(
  App,
  Effect.gen(function* () {
    const ss = yield* SessionStore;
    return App.of({
      whoami: (token) => Effect.map(ss.get(token.replace("tok_", "")), (s) => s ?? "anonymous")
    });
  })
);

// Provide the sub-bundle into AppLive before merging
const AppWired = Layer.provide(AppLive, AuthBundle);
const LiveLayer = Layer.merge(AuthBundle, AppWired);

const program = Effect.gen(function* () {
  const app = yield* App;
  return yield* app.whoami("tok_42");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`Layer.provide(AppLive, AuthBundle)` closes off App's requirements locally; the outer merge keeps the bundle visible for anything else that might need it.

```ts
import { Effect, Layer, Context } from "effect";

interface Env { readonly get: (k: string) => string | undefined }
const Env = Context.GenericTag<Env>("cli/Env");

interface ArgParser { readonly parse: (argv: ReadonlyArray<string>) => Effect.Effect<Record<string, string>> }
const ArgParser = Context.GenericTag<ArgParser>("cli/ArgParser");

interface LoadedConfig { readonly verbose: boolean; readonly target: string }
interface ConfigLoader { readonly load: (argv: ReadonlyArray<string>) => Effect.Effect<LoadedConfig> }
const ConfigLoader = Context.GenericTag<ConfigLoader>("cli/ConfigLoader");

interface Runner { readonly run: (argv: ReadonlyArray<string>) => Effect.Effect<string> }
const Runner = Context.GenericTag<Runner>("cli/Runner");

const EnvLive = Layer.succeed(Env, { get: (k) => ({ VERBOSE: "1" } as Record<string, string>)[k] });
const ArgParserLive = Layer.succeed(ArgParser, {
  parse: (argv) => Effect.succeed(Object.fromEntries(argv.map((a, i) => [`arg${i}`, a])))
});

// ConfigLoader depends on Env + ArgParser
const ConfigLoaderLive = Layer.effect(
  ConfigLoader,
  Effect.gen(function* () {
    const env = yield* Env;
    const parser = yield* ArgParser;
    return ConfigLoader.of({
      load: (argv) => Effect.gen(function* () {
        const args = yield* parser.parse(argv);
        return { verbose: env.get("VERBOSE") === "1", target: args.arg0 ?? "default" };
      })
    });
  })
);

// Runner depends on ConfigLoader
const RunnerLive = Layer.effect(
  Runner,
  Effect.gen(function* () {
    const loader = yield* ConfigLoader;
    return Runner.of({
      run: (argv) => Effect.gen(function* () {
        const cfg = yield* loader.load(argv);
        return `run(target=${cfg.target}, verbose=${cfg.verbose})`;
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(EnvLive, ArgParserLive, ConfigLoaderLive, RunnerLive);

const program = Effect.gen(function* () {
  const r = yield* Runner;
  return yield* r.run(["build"]);
});

export const runnable = Effect.provide(program, LiveLayer);
```

A clean four-layer graph: `Env` and `ArgParser` are leaf services; `ConfigLoader` fans them in; `Runner` consumes the result; `Layer.mergeAll` closes it all under `Effect.provide`.
